  results: T[];
}

export class ApiClient {
  constructor(
    private readonly ctx: APIRequestContext,
    private readonly token: string,
    private readonly baseUrl: string,
  ) {}

  private headers() {
    return authHeaders(this.token);
  }

  // ── Categories ──────────────────────────────────────────────────────────

